mapper.select:
SELECT COUNT(*) > 0
FROM trip_plan_members
WHERE plan_id = #{planId} AND user_id = #{userId}

SELECT COUNT(*)
FROM trip_plan_items
WHERE plan_id = #{planId} AND visit_date = #{visitDate}

SELECT plan_id, owner_id, title, start_date, end_date
FROM trip_plans
WHERE plan_id = #{planId}

mapper.update:
UPDATE trip_plans

    title = #{title},
    start_date = #{startDate},
    end_date = #{endDate}

WHERE plan_id = #{planId}

mapper.select:
SELECT item_id, plan_id, place_id, user_id, visit_date, item_order, visit_time, cost, memo
FROM trip_plan_items
WHERE item_id = #{itemId}

mapper.update:
UPDATE trip_plan_items

    visit_date = #{visitDate},
    visit_time = #{visitTime},
    cost = #{cost},
    memo = #{memo}

WHERE item_id = #{itemId}

UPDATE trip_plan_items
SET item_order = #{order}
WHERE item_id = #{itemId}
